// Parse all workflows, extract metadata, compare hashes, generate descriptions
const workflows = $('Get Export Workflows').all();
const registryRows = $input.all();

// Build lookup of existing registry entries by workflow ID
const existingMap = {};
for (const row of registryRows) {
  const r = row.json;
  if (r['Workflow ID']) {
    existingMap[r['Workflow ID']] = {
      hash: r['Structure Hash'] || '',
      description: r['Description'] || '',
      lastUpdated: r['Last Updated'] || ''
    };
  }
}

const results = [];

for (const item of workflows) {
  const wf = item.json;
  const nodes = wf.nodes || [];
  const connections = wf.connections || {};

  // --- Parse trigger type ---
  let triggerType = 'manual';
  for (const node of nodes) {
    const t = node.type || '';
    if (t.includes('scheduleTrigger')) { triggerType = 'schedule'; break; }
    if (t.includes('webhook') || t.includes('Webhook')) { triggerType = 'webhook'; break; }
    if (t.includes('slackTrigger')) { triggerType = 'slack'; break; }
    if (t.includes('executeWorkflowTrigger')) { triggerType = 'sub-workflow'; break; }
    if (t.includes('manualTrigger')) { triggerType = 'manual'; }
  }

  // --- Parse output destinations ---
  const outputs = new Set();
  for (const node of nodes) {
    const t = (node.type || '').toLowerCase();
    if (t.includes('slack') && !t.includes('trigger')) outputs.add('Slack');
    if (t.includes('clickup')) outputs.add('ClickUp');
    if (t.includes('googlesheets')) outputs.add('Google Sheets');
    if (t.includes('googledrive')) outputs.add('Google Drive');
    if (t.includes('gmail') || t.includes('emailsend')) outputs.add('Email');
    if (t.includes('github')) outputs.add('GitHub');
    if (t.includes('datatable')) outputs.add('n8n DataTable');
    if (t.includes('executeworkflow') && !t.includes('trigger')) outputs.add('Sub-workflow');
    if (t.includes('httprequest')) outputs.add('HTTP API');
    if (t.includes('missive') || (node.parameters?.url || '').includes('missive')) outputs.add('Missive');
  }

  // --- Parse sub-workflow calls ---
  const subWorkflows = [];
  for (const node of nodes) {
    if ((node.type || '').includes('executeWorkflow') && !(node.type || '').includes('Trigger')) {
      const wfId = node.parameters?.workflowId?.value || node.parameters?.workflowId || '';
      subWorkflows.push(`${node.name} → ${wfId}`);
    }
  }

  // --- Parse input schema (sub-workflows) ---
  let inputSchema = '';
  for (const node of nodes) {
    if ((node.type || '').includes('executeWorkflowTrigger')) {
      const inputs = node.parameters?.workflowInputs?.values || [];
      inputSchema = inputs.map(i => `${i.name}: ${i.type || 'string'}`).join(', ');
    }
  }

  // --- Compute structure hash ---
  const nodeTypes = nodes.map(n => `${n.type}:${n.name}`).sort().join('|');
  const connKeys = Object.entries(connections).map(([k, v]) => {
    const targets = (v.main || []).flat().map(c => c.node).join(',');
    return `${k}->${targets}`;
  }).sort().join('|');
  const hashInput = nodeTypes + '::' + connKeys;
  let hash = 0;
  for (let i = 0; i < hashInput.length; i++) {
    hash = ((hash << 5) - hash) + hashInput.charCodeAt(i);
    hash = hash & hash;
  }
  const structureHash = Math.abs(hash).toString(16);

  // --- Check if description needs generation ---
  const existing = existingMap[wf.id];
  const needsDescription = !existing || existing.hash !== structureHash;

  // --- Generate or preserve description ---
  let description = '';
  if (needsDescription) {
    const triggerDesc = {
      'schedule': 'Runs on a schedule',
      'webhook': 'Triggered by webhook',
      'slack': 'Triggered by Slack events',
      'sub-workflow': 'Called as a sub-workflow',
      'manual': 'Manually triggered'
    }[triggerType] || 'Manually triggered';
    const outputList = Array.from(outputs);
    const outputDesc = outputList.length > 0 ? `Outputs to ${outputList.join(', ')}.` : '';
    const subDesc = subWorkflows.length > 0 ? `Calls: ${subWorkflows.map(s => s.split(' →')[0]).join(', ')}.` : '';
    description = `${triggerDesc}. ${outputDesc} ${subDesc}`.trim();
  } else {
    description = existing.description;
  }

  // --- Generate clean filename ---
  const filename = wf.name
    .replace(/^\[(\d+[a-z]?)\]\s*/i, '$1-')
    .replace(/^\[T\]\s*/i, 'tool-')
    .replace(/[^a-zA-Z0-9\-]/g, '-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .toLowerCase() + '.json';

  // --- Check if GitHub push needed ---
  const needsGitHubPush = !existing || existing.lastUpdated !== wf.updatedAt;

  // --- Build clean workflow JSON (strip sensitive data) ---
  const cleanWf = { ...wf };
  delete cleanWf.shared;
  delete cleanWf.activeVersion;
  const workflowJson = JSON.stringify(cleanWf, null, 2);

  results.push({
    json: {
      workflowId: wf.id,
      name: wf.name,
      active: wf.active,
      triggerType,
      description,
      inputSchema,
      outputDestinations: Array.from(outputs).join(', '),
      subWorkflowsCalled: subWorkflows.join('; '),
      tags: (wf.tags || []).map(t => t.name).join(', '),
      nodeCount: nodes.length,
      errorHandler: wf.settings?.errorWorkflow || '',
      structureHash,
      needsGitHubPush,
      needsDescription,
      filename,
      workflowJson,
      lastUpdated: wf.updatedAt,
      lastChecked: new Date().toISOString()
    }
  });
}

return results;

// Prepare GitHub PUT body with base64 content and SHA if updating
const shaResponse = $input.first().json;
const workflow = $('SplitInBatches').first().json;

const content = Buffer.from(workflow.workflowJson).toString('base64');

const body = {
  message: `Auto-export: ${workflow.name}`,
  content: content
};

// If file already exists, include SHA for update
if (shaResponse && shaResponse.sha) {
  body.sha = shaResponse.sha;
}

return [{
  json: {
    url: `https://api.github.com/repos/alex-ahbadvisors/alex-os-automations/contents/n8n-workflows/${workflow.filename}`,
    body: body
  }
}];
